func TestReadyAndBlocked(t *testing.T) {
	s := newTestStore(t)

	a := &Bead{Title: "First"}
	b := &Bead{Title: "Second"}
	require.NoError(t, s.Create(testCtx(), a))
	require.NoError(t, s.Create(testCtx(), b))
	require.NoError(t, s.DepAdd(b.ID, a.ID))

	// B is blocked by A
	ready, err := s.Ready()
	require.NoError(t, err)
	assert.Len(t, ready, 1)
	assert.Equal(t, a.ID, ready[0].ID)

	blocked, err := s.Blocked()
	require.NoError(t, err)
	assert.Len(t, blocked, 1)
	assert.Equal(t, b.ID, blocked[0].ID)

	// Close A, B becomes ready
	require.NoError(t, s.Close(testCtx(), a.ID))

	ready, err = s.Ready()
	require.NoError(t, err)
	assert.Len(t, ready, 1)
	assert.Equal(t, b.ID, ready[0].ID)

	blocked, err = s.Blocked()
	require.NoError(t, err)
	assert.Len(t, blocked, 0)
}

func TestDepAddValidation(t *testing.T) {
	s := newTestStore(t)

	a := &Bead{Title: "A"}
	require.NoError(t, s.Create(testCtx(), a))

	// Dep on nonexistent
	err := s.DepAdd(a.ID, "nonexistent")
	assert.Error(t, err)
	assert.Contains(t, err.Error(), "dependency not found")

	// Self-dep
	err = s.DepAdd(a.ID, a.ID)
	assert.Error(t, err)
	assert.Contains(t, err.Error(), "cannot depend on self")

	// Idempotent add
	b := &Bead{Title: "B"}
	require.NoError(t, s.Create(testCtx(), b))
	require.NoError(t, s.DepAdd(b.ID, a.ID))
	require.NoError(t, s.DepAdd(b.ID, a.ID)) // no error on duplicate
}

func TestBeadDepAddRejectsParentAncestor(t *testing.T) {
	s := newTestStore(t)

	root := &Bead{Title: "Root"}
	parent := &Bead{Title: "Parent"}
	child := &Bead{Title: "Child"}
	require.NoError(t, s.Create(testCtx(), root))
	require.NoError(t, s.Create(testCtx(), parent))
	require.NoError(t, s.Create(testCtx(), child))

	require.NoError(t, s.Update(testCtx(), parent.ID, func(b *Bead) {
		b.Parent = root.ID
	}))
	require.NoError(t, s.Update(testCtx(), child.ID, func(b *Bead) {
		b.Parent = parent.ID
	}))

	t.Run("direct-parent", func(t *testing.T) {
		err := s.DepAdd(child.ID, parent.ID)
		require.Error(t, err)
		assert.Contains(t, err.Error(), "ancestor in the parent chain")
		assert.Contains(t, err.Error(), parent.ID)
		assert.Contains(t, err.Error(), parent.ID+" -> "+root.ID)
	})

	t.Run("grandparent-ancestor", func(t *testing.T) {
		err := s.DepAdd(child.ID, root.ID)
		require.Error(t, err)
		assert.Contains(t, err.Error(), "ancestor in the parent chain")
		assert.Contains(t, err.Error(), root.ID)
		assert.Contains(t, err.Error(), parent.ID+" -> "+root.ID)
	})
}

func TestDepRemove(t *testing.T) {
	s := newTestStore(t)

	a := &Bead{Title: "A"}
	b := &Bead{Title: "B"}
	require.NoError(t, s.Create(testCtx(), a))
	require.NoError(t, s.Create(testCtx(), b))
	require.NoError(t, s.DepAdd(b.ID, a.ID))

	got, _ := s.Get(testCtx(), b.ID)
	assert.Contains(t, got.DepIDs(), a.ID)

	require.NoError(t, s.DepRemove(b.ID, a.ID))
	got, _ = s.Get(testCtx(), b.ID)
	assert.NotContains(t, got.DepIDs(), a.ID)
}

func TestDepTree(t *testing.T) {
	s := newTestStore(t)

	a := &Bead{Title: "Root task"}

// Package bead implements the on-disk bead tracker.
//
// Size envelope (ddx-f8a11202):
//
// Individual bead fields — description, acceptance, notes, and each event's
// body — are bounded by MaxFieldBytes (65,535 bytes). This matches upstream
// bd's Dolt TEXT column limit so DDx-authored beads can always round-trip
// through `bd import`. Writers exceeding the cap are truncated with a
// `…[truncated, N bytes]` marker at AppendEvent; callers that need to
// preserve the full payload (notably reviewer streams) should persist to a
// sidecar artifact under `.ddx/executions/<id>/` and record a path
// reference in the event body.
//
// On the read side, scanners use a 16MB buffer — real-world incidents have
// produced 1.46MB bead rows and ~7MB session-log rows when writers bypassed
// the cap. 16MB comfortably fits a bead with dozens of maxed-out fields and
// matches the scanner in the agent package.
package bead

import (
	"bufio"
	"bytes"
	"context"
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
)

// Store manages beads via a pluggable backend.
type Store struct {
	Collection string
	Dir        string
	File       string
	Prefix     string
	LockDir    string
	LockWait   time.Duration
	backend    RawBackend // nil means use built-in JSONL
}

// Compile-time check: *Store satisfies the high-level Backend interface
// declared in backend.go. This is the contract chaos_test.go and (eventually)
// cli/cmd callers program against.
var _ Backend = (*Store)(nil)

type StoreOption func(*Store)

// WithCollection selects the logical bead collection. The default collection
// remains "beads", which maps to "beads.jsonl" in the JSONL backend.
func WithCollection(name string) StoreOption {
	return func(s *Store) {
		if cleaned := normalizeCollection(name); cleaned != "" {
			s.Collection = cleaned
		}
	}
}

// NewStore creates a store with the given directory.
// Defaults can be overridden via options or environment.
func NewStore(dir string, opts ...StoreOption) *Store {
	if dir == "" {
		dir = envOr("DDX_BEAD_DIR", ".ddx")
	}
	workingDir := dir
	if filepath.Base(dir) == ".ddx" {
		workingDir = filepath.Dir(dir)
	}
	prefix := envOr("DDX_BEAD_PREFIX", "")
	var configBackend string
	if cfg, err := config.LoadWithWorkingDir(workingDir); err == nil && cfg != nil && cfg.Bead != nil {
		if prefix == "" && cfg.Bead.IDPrefix != "" {
			prefix = cfg.Bead.IDPrefix
		}
		configBackend = cfg.Bead.Backend
	}
	if prefix == "" {
		prefix = detectPrefix(workingDir)
	}
	// Backend selection: env var wins, then config, then jsonl default.
	backendType := os.Getenv("DDX_BEAD_BACKEND")
	if backendType == "" {
		backendType = configBackend
	}
	if backendType == "" {
		backendType = BackendJSONL
	}

	s := &Store{
		Collection: DefaultCollection,
		Dir:        dir,
		Prefix:     prefix,
		LockWait:   parseDurationOr("DDX_BEAD_LOCK_TIMEOUT", 10*time.Second),
	}
	for _, opt := range opts {
		if opt != nil {
			opt(s)
		}
	}
	spec := DefaultRegistry().Resolve(CollectionID(s.Collection))
	s.File, s.LockDir = spec.PathsUnder(dir)

	// Set up external backend if configured. bd/br lack per-collection
	// scoping in their CLI, so non-default collections (e.g. beads-archive)
	// route through a JSONL fallback the external backend transparently
	// delegates to. The default collection always goes straight to bd/br
	// to preserve the existing interchange contract (schema_compat_test.go,
	// import/export round-trip).
	switch backendType {
	case BackendBD, BackendBR:
		var fallback RawBackend
		if s.Collection != DefaultCollection {
			fallback = NewJSONLBackend(s.Dir, s.File, s.LockDir, s.LockWait)
		}
		if ext, err := NewExternalBackendWithFallback(backendType, s.Collection, fallback); err == nil {
			s.backend = ext
		}
		// Fall through to JSONL if tool not available
	case BackendAxon:
		s.backend = NewAxonBackend(s.Dir, s.LockWait)
	}

	return s
}

// NewStoreWithCollection creates a store for a named logical collection.
func NewStoreWithCollection(dir, collection string) *Store {
	return NewStore(dir, WithCollection(collection))
}

// Init creates the storage directory and file.
func (s *Store) Init(ctx context.Context) error {
	if err := ctx.Err(); err != nil {
		return err
	}
	if s.backend != nil {
		return s.backend.Init()
	}
	if err := os.MkdirAll(s.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: init dir: %w", err)
	}
	f, err := os.OpenFile(s.File, os.O_CREATE|os.O_WRONLY, 0o644)
	if err != nil {
		return fmt.Errorf("bead: init file: %w", err)
	}
	return f.Close()
}

// GenID generates a unique bead ID with the configured prefix.
func (s *Store) GenID(ctx context.Context) (string, error) {
	if err := ctx.Err(); err != nil {
		return "", err
	}
	prefix := s.Prefix
	if prefix == "" {
		prefix = DefaultIDPrefix
	} else if !strings.HasSuffix(prefix, "-") {
		prefix += "-"
	}
	return RandomHexIDGenerator{Prefix: prefix, Bytes: 4}.GenID(ctx)
}

// ReadAll loads all beads from the configured backend.
func (s *Store) ReadAll(ctx context.Context) ([]Bead, error) {
	if err := ctx.Err(); err != nil {
		return nil, err
	}
	if s.backend != nil {
		all, err := s.backend.ReadAll()
		if err != nil {
			return nil, err
		}
		return all, nil
	}
	beads, warnings, err := s.readAllRaw()
	if err != nil {
		return nil, fmt.Errorf("bead: read %s: %w", s.File, err)
	}
	beads = foldLatestBeads(beads)
	for _, warning := range warnings {
		fmt.Fprintln(os.Stderr, warning)
	}
	if len(warnings) > 0 && len(beads) > 0 {
		repaired, repairErr := s.repairJSONL()
		if repairErr != nil {
			return beads, fmt.Errorf("bead: repair %s: %w", s.File, repairErr)
		}
		if repaired {
			fmt.Fprintf(os.Stderr, "bead: repaired %s; backup written to %s.bak\n", s.File, s.File)
		}
	}
	if len(beads) == 0 && len(warnings) > 0 {
		return nil, fmt.Errorf("bead: read %s: %d malformed record(s), 0 valid", s.File, len(warnings))
	}
	return beads, nil
}

// ReadAllFiltered loads all beads, folds them by latest-wins, and returns only
// those for which the predicate returns true. When the predicate is nil every
// bead is returned (equivalent to ReadAll). The predicate is applied at the
// per-entry parse boundary after fold — matched beads are appended directly to
// the return slice without first being held in an intermediate full-corpus
// list, so queries that match a small subset avoid materializing the
// mismatches (ddx-9ce6842a Part 2 step 2: filter pushdown).
func (s *Store) ReadAllFiltered(ctx context.Context, pred func(Bead) bool) ([]Bead, error) {
	if err := ctx.Err(); err != nil {
		return nil, err
	}
	if s.backend != nil {
		all, err := s.backend.ReadAll()
		if err != nil {
			return nil, err
		}
		if pred == nil {
			return all, nil
		}
		out := make([]Bead, 0, len(all))
		for _, b := range all {
			if pred(b) {
				out = append(out, b)
			}
		}
		return out, nil
	}
	beads, warnings, err := s.readAllRaw()
	if err != nil {
		return nil, fmt.Errorf("bead: read %s: %w", s.File, err)
	}
	beads = foldLatestBeads(beads)
	for _, warning := range warnings {
		fmt.Fprintln(os.Stderr, warning)
	}
	if len(warnings) > 0 && len(beads) > 0 {
		repaired, repairErr := s.repairJSONL()
		if repairErr != nil {
			return beads, fmt.Errorf("bead: repair %s: %w", s.File, repairErr)
		}
		if repaired {
			fmt.Fprintf(os.Stderr, "bead: repaired %s; backup written to %s.bak\n", s.File, s.File)
		}
	}
	if len(beads) == 0 && len(warnings) > 0 {
		return nil, fmt.Errorf("bead: read %s: %d malformed record(s), 0 valid", s.File, len(warnings))
	}
	if pred == nil {
		return beads, nil
	}
	out := make([]Bead, 0, len(beads))
	for _, b := range beads {
		if pred(b) {
			out = append(out, b)
		}

	}
	for _, label := range b.Labels {
		switch label {
		case "action:review", "kind:review", "phase:review", "review-finding":
			return true
		}
	}
	return false
}

func (f *CommandFactory) beadWorkspaceRoot() string {
	dir := os.Getenv("DDX_BEAD_DIR")
	if dir != "" {
		if filepath.Base(dir) == ".ddx" {
			if !filepath.IsAbs(dir) && f.WorkingDir != "" {
				if workspaceRoot := gitpkg.FindNearestDDxWorkspace(f.WorkingDir); workspaceRoot != "" {
					return workspaceRoot
				}
				dir = filepath.Join(f.WorkingDir, dir)
			}
			return filepath.Dir(dir)
		}
		if !filepath.IsAbs(dir) && f.WorkingDir != "" {
			return filepath.Join(f.WorkingDir, dir)
		}
		return dir
	}
	if f.WorkingDir == "" {
		return ""
	}
	if workspaceRoot := gitpkg.FindNearestDDxWorkspace(f.WorkingDir); workspaceRoot != "" {
		return workspaceRoot
	}
	return f.WorkingDir
}

func (f *CommandFactory) beadStore() *bead.Store {
	workspaceRoot := f.beadWorkspaceRoot()
	if workspaceRoot == "" {
		return bead.NewStore("")
	}
	return bead.NewStore(ddxroot.JoinProject(workspaceRoot))
}

func (f *CommandFactory) newBeadInitCommand() *cobra.Command {
	return &cobra.Command{
		Use:   "init",
		Short: "Initialize bead storage",
		Args:  cobra.NoArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			s := f.beadStore()
			if err := s.Init(context.Background()); err != nil {
				return err
			}
			fmt.Fprintf(cmd.OutOrStdout(), "Initialized bead storage at %s\n", s.File)

			// Auto-migrate from .helix/issues.jsonl if present
			n, migrated, err := s.MigrateFromHelix()
			if err != nil {
				fmt.Fprintf(cmd.ErrOrStderr(), "Warning: migration from .helix/issues.jsonl failed: %v\n", err)
			} else if migrated {
				fmt.Fprintf(cmd.OutOrStdout(), "Migrated %d beads from .helix/issues.jsonl\n", n)
			}
			return nil
		},
	}
}

func (f *CommandFactory) newBeadCreateCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "create <title>",
		Short: "Create a new bead",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			if err := f.checkLifecycleMigrationGate(cmd); err != nil {
				return err
			}
			s := f.beadStore()
			b := &bead.Bead{Title: args[0]}

			if v, _ := cmd.Flags().GetString("type"); v != "" {
				b.IssueType = v
			}
			if v, _ := cmd.Flags().GetInt("priority"); cmd.Flags().Changed("priority") {
				b.Priority = v
			}
			if v, _ := cmd.Flags().GetString("labels"); v != "" {
				b.Labels = strings.Split(v, ",")
			}
			if v, _ := cmd.Flags().GetString("acceptance"); v != "" {
				b.Acceptance = v
			}
			if v, _ := cmd.Flags().GetString("description"); v != "" {
				b.Description = v
			}
			if v, _ := cmd.Flags().GetString("parent"); v != "" {
				b.Parent = v
			}
			if dependsOn, _ := cmd.Flags().GetStringSlice("depends-on"); len(dependsOn) > 0 {
				normalized := make([]string, 0, len(dependsOn))
				for _, depID := range dependsOn {
					if depID = strings.TrimSpace(depID); depID != "" {
						normalized = append(normalized, depID)
					}
				}
				if len(normalized) > 0 {
					if b.ID == "" {
						id, err := s.GenID(context.Background())
						if err != nil {
							return err
						}
						b.ID = id
					}
					for _, depID := range normalized {
						b.AddDep(depID, "blocks")
					}
				}
			}
			if setFlags, _ := cmd.Flags().GetStringArray("set"); len(setFlags) > 0 {
				if b.Extra == nil {
					b.Extra = make(map[string]any)
				}
				for _, kv := range setFlags {
					k, v, ok := strings.Cut(kv, "=")
					if !ok {
						return fmt.Errorf("--set requires key=value format, got: %s", kv)
					}
					switch v {
					case "true":
						b.Extra[k] = true
					case "false":
						b.Extra[k] = false
					default:
						b.Extra[k] = v
					}
				}
			}

			if err := f.withBeadTrackerWriteLock(func() error {
				if err := s.Create(context.Background(), b); err != nil {
					return err
				}
				if markerPresent, _ := s.HasLifecycleSchemaMarker(); !markerPresent && !beadHasLegacyLifecycleInputs(*b) {
					if err := s.WriteLifecycleSchemaMarker(time.Now().UTC()); err != nil {
						return err
					}
				}
				if _, err := f.beadAutoCommitPaths("create "+b.ID, []string{s.File, s.LifecycleSchemaMarkerPath()}); err != nil {
					return err
				}
				return nil
			}); err != nil {
				return err
			}
			fmt.Fprintf(cmd.OutOrStdout(), "%s\n", b.ID)
			return nil
		},
	}

	cmd.Flags().String("type", "", "Bead type (task, bug, epic, chore)")
	cmd.Flags().Int("priority", 2, "Priority (0=highest, 4=lowest)")
	cmd.Flags().String("labels", "", "Comma-separated labels")
	cmd.Flags().String("acceptance", "", "Acceptance criteria")
	cmd.Flags().String("description", "", "Description")
	cmd.Flags().String("parent", "", "Parent bead ID")
	cmd.Flags().StringSlice("depends-on", nil, "Dependency bead ID (comma-separated or repeated)")
	cmd.Flags().StringArray("set", nil, "Set custom field (key=value, repeatable)")

	return cmd
}

